/*-----------------
 *  PUBLIC FONT
 *----------------*/

/*Initialize a public general font descriptor*/

const chinese_font_t_4bit chinese_font_16_4bit = {

    .dsc = &font_dsc_4bit,
    .line_height = 23,
    .base_line = 5,
    .subpx = 0,
    .underline_position = -2,
    .underline_thickness = 1,
    .user_data = NULL};

const chinese_font_glyph_dsc_t_4bit *chinese_font_get_glyph_4bit(uint32_t unicode)
{
  for (int i = 0; i < chinese_font_cmap_num; i++)
  {
    const chinese_font_cmap_t_4bit *cmap = &chinese_font_cmaps_4bit[i];

    if (unicode < cmap->range_start ||
        unicode >= cmap->range_start + cmap->range_length)
      continue;

    uint16_t glyph_id = 0;

    switch (cmap->type)
    {
    case chinese_font_cmap_num:
      /* 连续区间映射 */
      glyph_id = cmap->glyph_id_start + (unicode - cmap->range_start);
      break;

    // case SIMSUN_CMAP_FORMAT0_FULL:
    //   /* 完整 offset 表 */
    //   glyph_id = cmap->glyph_id_start + cmap->glyph_id_ofs_list[unicode - cmap->range_start];
    //   break;

    case CHINESE_FONT_CMAP_SPARSE_TINY:
      /* 稀疏表查找 */
      for (int j = 0; j < cmap->list_length; j++)
      {
        if (unicode == cmap->range_start + cmap->unicode_list[j])
        {
          glyph_id = cmap->glyph_id_start + j;
          break;
        }
      }
      break;
    }

    if (glyph_id > 0)
    {
      return &chinese_font_glyph_dsc_4bit[glyph_id];
    }
  }
  return nullptr;
}
